import React, { useState, useEffect } from 'react';
import { getAllFeedback, respondToFeedback } from '../../services/dataService';
import { formatDate } from '../../utils/helpers';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import { FiStar, FiMessageSquare } from 'react-icons/fi';

const AdminFeedback = () => {
  const [feedbacks, setFeedbacks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [responding, setResponding] = useState(null);
  const [response, setResponse] = useState('');

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const res = await getAllFeedback();
      setFeedbacks(res.data.data);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const handleRespond = async (id) => {
    try {
      await respondToFeedback(id, { adminResponse: response });
      setResponding(null);
      setResponse('');
      fetchData();
    } catch (err) { console.error(err); }
  };

  const filtered = filter === 'all' ? feedbacks : feedbacks.filter(f => f.status === filter);

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header"><h1>Feedback Management</h1></div>
      <div className="filters-bar">
        {['all', 'submitted', 'reviewed', 'responded'].map(f => (
          <button key={f} className={`btn btn-sm ${filter === f ? 'btn-primary' : 'btn-outline'}`} onClick={() => setFilter(f)}>
            {f.charAt(0).toUpperCase() + f.slice(1)}
          </button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <div className="empty-state"><p>No feedback found</p></div>
      ) : (
        <div>
          {filtered.map(f => (
            <div key={f._id} className="card" style={{ marginBottom: '16px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <div>
                  <h3>{f.title}</h3>
                  <div style={{ display: 'flex', gap: '8px', alignItems: 'center', marginBottom: '8px' }}>
                    <span><strong>{f.customer?.name || 'Unknown'}</strong></span>
                    <StatusBadge status={f.category} />
                    <StatusBadge status={f.status} />
                    <span style={{ display: 'flex', gap: '2px' }}>
                      {[...Array(5)].map((_, i) => (
                        <FiStar key={i} fill={i < f.rating ? '#ffd166' : 'none'} color="#ffd166" size={14} />
                      ))}
                    </span>
                  </div>
                  <p>{f.message}</p>
                </div>
                <small>{formatDate(f.createdAt)}</small>
              </div>

              {f.adminResponse && (
                <div style={{ marginTop: '12px', padding: '12px', background: '#f8f9fa', borderRadius: '8px' }}>
                  <strong>Your Response:</strong>
                  <p>{f.adminResponse}</p>
                </div>
              )}

              {!f.adminResponse && (
                <div style={{ marginTop: '12px' }}>
                  {responding === f._id ? (
                    <div>
                      <textarea className="form-control" value={response} onChange={(e) => setResponse(e.target.value)} rows="3" placeholder="Write your response..." />
                      <div className="btn-group" style={{ marginTop: '8px' }}>
                        <button className="btn btn-sm btn-primary" onClick={() => handleRespond(f._id)}>Send Response</button>
                        <button className="btn btn-sm btn-secondary" onClick={() => { setResponding(null); setResponse(''); }}>Cancel</button>
                      </div>
                    </div>
                  ) : (
                    <button className="btn btn-sm btn-outline" onClick={() => setResponding(f._id)}><FiMessageSquare /> Respond</button>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default AdminFeedback;
